$ErrorActionPreference = "Stop"
$ProjectRoot = Split-Path -Parent $PSScriptRoot
$Target = Join-Path $ProjectRoot "SQL\schema_v1.sql"
$Utf8NoBom = New-Object System.Text.UTF8Encoding($false)
$Content = [System.Text.Encoding]::UTF8.GetString(
    [System.Convert]::FromBase64String("")
)
[System.IO.File]::WriteAllText($Target, $Content, $Utf8NoBom)

$Length = (Get-Item $Target).Length
if ($Length -lt 1000) {
    throw "Schema write failed or produced an unexpectedly small file: $Length bytes"
}

Write-Host "Repaired SQL\schema_v1.sql"
Write-Host "Length: $Length bytes"
